import React, { useState, useEffect, useRef } from 'react';
import { DataTable } from 'primereact/datatable';
import { Column } from 'primereact/column';
import { Toast } from 'primereact/toast';
import Loading from '../../components/Loading';
import axios from 'axios';
import { BASE_URL } from '../../helpers/BaseUrl';
import { Dropdown } from 'primereact/dropdown';
import Error from '../../components/Error';

import { Panel } from 'primereact/panel';



export default function Debtor() {
   
    const statuses = [ {"id":0,"status":true,"name":"Si"},{"id":1,"status":false,"name":"No"}]
    const toast = useRef(null);
    let today = new Date();

    const [course, setCourse] = useState(null);
    const [year, setYear] = useState(today.getFullYear());
    const [month, setMonth] = useState(today.getMonth());
    const [languajes, setLanguajes] = useState(null);
    const [languaje, setLanguaje] = useState(null);
    const [courses, setCourses] = useState(null);
    const [chargingCourse, setChargingCourse] = useState(false);
    const [showError, setShowError] = useState(false);
    const [loading, setLoading] = useState(false);
    const [years, setYears] = useState(null);
    const [months, setMonths] = useState(null);
    const [invoices, setInvoices] = useState(null);
    const [status, setStatus] = useState(true);
    const [filtering, setFiltering] = useState(false); // eslint-disable-line no-unused-vars

    useEffect(() => {
        async function loadLanguajes() {
            try {
                await axios.get(`${BASE_URL}/api/years`).then(({ data: { data:  years} }) => {
                    setYears(years);
                });
                await axios.get(`${BASE_URL}/api/months`).then(({ data: { data:  months} }) => {
                    months.splice(12, 1);
                    setMonths(months);
                });
                await axios.get(`${BASE_URL}/api/languajes?all=1`).then(({ data: { data: { data: languajes } } }) => {
                    setLanguajes(languajes);
                    setCourses(null);
                    setLoading(false)
                });
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de idiomas');
                setShowError(true);
            }
        }
        loadLanguajes();
    }, []);

    useEffect(() => {
        async function loadCourses() {
            try {
                if (languaje !=null){
                    setChargingCourse(true)
                    setCourses(null);
                    await axios.get(`${BASE_URL}/api/languajes/${languaje}/courses?all=1`).then(({ data: { data: { data: courses } } }) => {
                        setCourses(courses);
                        setChargingCourse(false)
                        setLoading(false)
                    });
                } 
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de cursos');
                setShowError(true);
                setChargingCourse(false)
                setLoading(false)
            }
        }
        loadCourses();
    }, [languaje]);


    useEffect(() => {
        async function  getInvoicesByFilter  ()  {
            try {
                setFiltering(true)
                if(languaje=== null || year ===null || month === null){
                    return;
                }
                if(languaje!== null || year !==null || month !== null || status !== null){
                    setLoading(true)

                }
                await axios.get(`${BASE_URL}/api/debtors?languaje=${languaje}&curso=${course}&year=${year}&month=${month}&status=${status}`).then(data => {
                    setInvoices(data.data.data)
                    setFiltering(false)
                    setLoading(false)

                }).catch ((error) => {
                    console.log(error);
                    console.warn('Hubo un problema con la carga de los deudores');
                    setShowError(true);
                    setFiltering(false)
                    setLoading(false)
                });
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de los deudores');
                setShowError(true);
                setFiltering(false)
                setLoading(false)
            }
        }
        getInvoicesByFilter();
    }, [languaje,year,month,course,status]);

    const LeftToolbarTemplate = () => {
        return (
            <div className="card">
                <div className="p-fluid p-formgrid p-grid">
                    <div className="p-field p-col-12 p-md-2">
                        <label htmlFor="yearpicker" className="p-d-block">Año</label>
                        <div className="p-d-flex">
                                <Dropdown appendTo={document.body} id="year" value={year} onChange={e => setYear(()=>{
                                    return e.target.value !== undefined ? e.target.value: null; 
                                })} options={years}  optionValue="name" optionLabel="name" filter showClear filterBy="name" placeholder="-- Seleccione año --" style={{ width: '14rem' }} className="p-mr-2"/>
                                    <label htmlFor="year" className="p-d-block">&nbsp;&nbsp;</label>       
                        </div>   
                    </div>
                    <div className="p-field p-col-12 p-md-2">
                        <label htmlFor="yearpicker" className="p-d-block">Mes</label>
                        <div className="p-d-flex">
                                <Dropdown appendTo={document.body} id="month" value={month} onChange={e => setMonth(()=>{
                                    return e.target.value !== undefined ? e.target.value: null; 
                                })} options={months}  optionValue="id" optionLabel="id" filter showClear filterBy="id" placeholder="-- Seleccione mes --" style={{ width: '14rem' }} className="p-mr-2"/>
                                    <label htmlFor="year" className="p-d-block">&nbsp;&nbsp;</label>       
                        </div>   
                    </div>
                    <div className="p-field p-col-12  p-md-3">
                            <label htmlFor="languaje" className="p-d-block">Idioma</label>
                            <Dropdown appendTo={document.body} id="languaje" value={languaje} onChange={e => setLanguaje(()=>{
                                return e.target.value !== undefined ? e.target.value: null;
                            })} options={languajes} optionLabel="name" optionValue="id" filter showClear filterBy="name" placeholder="-- Seleccione idioma --" style={{ width: '14rem' }} />
                    </div>
                    <div className="p-field p-col-12 p-md-3">
                        <label htmlFor="course" className="p-d-block">Curso</label>
                        <div style={{ position: 'relative' }}>
                            <Dropdown appendTo={document.body} id="course" value={course} onChange={e => setCourse(()=>{
                                return e.target.value !== undefined ? e.target.value: null;
                            })} options={courses} optionLabel="nameId" optionValue="id" filter showClear filterBy="nameId"
                                disabled={chargingCourse}
                                placeholder={chargingCourse ? 'Cargando cursos...' : '-- Seleccione curso --'}
                            />
                            {chargingCourse && (
                                <i className="pi pi-spin pi-spinner" style={{
                                    position: 'absolute', right: 38, top: '50%',
                                    transform: 'translateY(-50%)',
                                    color: '#3ab54a', fontSize: '0.85rem', pointerEvents: 'none',
                                }} />
                            )}
                        </div>
                    </div>
                    <div className="p-field p-col-12 p-md-2">
                        <label htmlFor="course" className="p-d-block">Alumnos activos</label>
                        <Dropdown appendTo={document.body} id="status" value={status} onChange={e => setStatus(()=>{
                            return e.target.value !== undefined ? e.target.value: null; 
                        })} options={statuses} optionLabel="name" optionValue="status" placeholder="-- Seleccione  --" />
                    </div>
                </div>
            </div>
        )
    }




    if (loading) {
        return (
            <Loading />
        );
    }

    if(showError){
        return(
            <Error mensaje={'Hubo un problema al cargar los registros de los de deudores'}></Error>
        );
    } 

    return (
        <div className="p-grid crud-demo">
            <div className="p-col-12">
                <div className="p-d-flex p-ai-center p-mb-3" style={{ gap: '1rem' }}>
                    <div style={{ width: 48, height: 48, borderRadius: 12, flexShrink: 0, background: 'linear-gradient(135deg, #3ab54a, #1a5c25)', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 14px rgba(58,181,74,0.35)' }}>
                        <i className="pi pi-money-bill" style={{ color: '#fff', fontSize: '1.4rem' }}></i>
                    </div>
                    <div>
                        <h2 className="p-m-0" style={{ color: '#1a3320', fontWeight: 800, fontSize: '1.45rem', lineHeight: 1.2 }}>Deudores</h2>
                        <p className="p-m-0" style={{ color: '#6c757d', fontSize: '0.875rem' }}>Consulta de deudas por idioma, nivel y curso</p>
                    </div>
                </div>
                <div className="card" style={{ borderRadius: 12, boxShadow: '0 2px 16px rgba(0,0,0,0.07)', border: 'none' }}>
                    <Toast ref={toast} />
                    <LeftToolbarTemplate />
                {invoices && 
                    invoices.map((invoiceLevel,id) =>{  
                        const keysLevel = Object.keys(invoiceLevel);
                        return (
                            <div key={id} >
                            {keysLevel.map((keyLevel,idLevel) =>{  
                                const invoiceCourses = invoiceLevel[keyLevel];
                                return (
                                        <Panel key={idLevel} header={keyLevel} toggleable>
                                        {invoiceCourses.map((invoiceCourse,idCurso) =>{
                                            const keyCourses = Object.keys(invoiceCourse);
                                            return (
                                                <div key={idCurso} >
                                                {keyCourses.map((keyCourse,idInvoice) =>{
                                                    var invoicess = [...invoiceCourse[keyCourse]];
                                                    var amountOwedTotal = invoicess[invoicess.length-1]; 
                                                    invoicess.splice( invoicess.length-1, 1);
                                                    return (
                                                        <Panel key={idInvoice} header={keyCourse} toggleable>
                                                                <DataTable value={invoicess} className="datatable-responsive datatable-compact">
                                                                    <Column field="id" header="Id"></Column>
                                                                    <Column field="student" header="Alumno"></Column>
                                                                    <Column field="lastDatePaid" header="Ultima fecha pago"></Column>
                                                                    <Column field="lastMonthPaid" header="Ultimo mes pagado"></Column>
                                                                    <Column field="monthsOwed" header="Meses adeudados"></Column>
                                                                    <Column field="monthFee" header="Cuota mensual"></Column>
                                                                    <Column field="amountOwed" header="Monto adeudado"></Column>
                                                                </DataTable>
                                                                {amountOwedTotal && amountOwedTotal.amountOwedTotal !== undefined ?
                                                                    <div className="table-header">
                                                                        <div className="p-col-6">
                                                                            <h3 className="p-m-0">Total</h3>
                                                                        </div>
                                                                        <div className="p-col-2"></div>
                                                                        <div className="p-col-2"></div>
                                                                        <div className="p-col-2">
                                                                            <span className="flex align-content-end"><h3>$ {amountOwedTotal.amountOwedTotal}</h3></span>
                                                                        </div>
                                                                    </div>
                                                                       
                                                                    :""
                                                                }
                                                               
                                                        </Panel>
                                                    )
                                                    
                                                })}
                                                </div>
                                            )
                                        })}
                                         </Panel>
                                )
                            })
                        }
                        </div>
                    )
                    })
                }
                </div>
            </div>
        </div>
    );

}