import React, { useState, useEffect, useRef } from 'react';
import { DataTable } from 'primereact/datatable';
import { Column } from 'primereact/column';
import { Toast } from 'primereact/toast';
import { Button } from 'primereact/button';
import Loading from '../../components/Loading';
import axios from 'axios';
import { BASE_URL } from '../../helpers/BaseUrl';
import { addLocale } from 'primereact/api';
import { Calendar } from 'primereact/calendar';
import { Dropdown } from 'primereact/dropdown';
import Error from '../../components/Error';


const FileDownload = require('js-file-download');


export default function ReportPaymentsByTeacher() {

    addLocale('es', {
        firstDayOfWeek: 1,
        dayNames: ['domingo', 'lunes', 'martes', 'miércoles', 'jueves', 'viernes', 'sábado'],
        dayNamesShort: ['dom', 'lun', 'mar', 'mié', 'jue', 'vie', 'sáb'],
        dayNamesMin: ['D', 'L', 'M', 'X', 'J', 'V', 'S'],
        monthNames: ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'],
        monthNamesShort: ['ene', 'feb', 'mar', 'abr', 'may', 'jun', 'jul', 'ago', 'sep', 'oct', 'nov', 'dic'],
        today: 'Hoy',
        clear: 'Claro'
    });
    const [showError, setShowError] = useState(false);

    const toast = useRef(null);
    const dt = useRef(null);

    const [dateInit, setDateInit] = useState(null);
    const [dateFinish, setDateFinish] = useState(null);
    const [calViewDate, setCalViewDate] = useState(new Date());
    const [teacher, setTeacher] = useState(null);
    const [loading, setLoading] = useState(false);
    const [schoolYear, setSchoolYear] = useState(null);
    const [schoolYears, setSchoolYears] = useState(null);
    const [month, setMonth] = useState(null);
    const [invoices, setInvoices] = useState(null);
    const [teachers, setTeachers] = useState(null);
    const [loadingDatatable, setLoadingDatatable] = useState(false);
    const [totalRecords, setTotalRecords] = useState(0);
    const [download, setDownload] = useState(false);

    const [lazyParams, setLazyParams] = useState({
        first: 0,
        rows: 10,
        page: 0,
    });
    useEffect(() => {
        async function loadSchoolYears() {
            try {
                await axios.get(`${BASE_URL}/api/schoolYears?all=1`).then(({ data: { data: { data: years } } }) => {
                    setSchoolYears(years);
                    const active = years.find(function(y) { return y.active === true; });
                    setSchoolYear(active || null);
                });
            } catch (error) {
                console.warn('Hubo un problema con la carga de los años lectivos');
            }
        }
        loadSchoolYears();
    }, []);

    useEffect(() => {
        if (schoolYear?.year) {
            setCalViewDate(new Date(Number(schoolYear.year), 0, 1));
        }
    }, [schoolYear]); // eslint-disable-line react-hooks/exhaustive-deps

    useEffect(() => {
        async function loadTeachers() {
            try {
                await axios.get(`${BASE_URL}/api/teachers?all=1`).then(({ data: { data: { data: teachers } } }) => {
                    setTeachers(teachers);
                });
                setLoading(false);
            } catch (error) {
                console.log(error)
                console.warn('Hubo un problema al cargar los registros de reportes de recibos de docentes');
                setShowError(true);
                setLoadingDatatable(false);
                setLoading(false)
            }
        }
        loadTeachers();
    }, []);

    function formatDate(date) {
        if (date === null || date === undefined) {
            return null;
        }
        var d = new Date(date),
            month = '' + (d.getMonth() + 1),
            day = '' + d.getDate(),
            year = d.getFullYear();

        if (month.length < 2)
            month = '0' + month;
        if (day.length < 2)
            day = '0' + day;

        return [year, month, day].join('-');
    }

    function formatMonth(date) {
        if (date === null || date === undefined) {
            return null;
        }
        var d = new Date(date),
            month = '' + (d.getMonth() + 1),
            day = '' + d.getDate(),
            year = d.getFullYear();

        if (month.length < 2)
            month = '0' + month;
        if (day.length < 2)
            day = '0' + day;

        return [year, month].join('-');
    }

    useEffect(() => {
        async function loadLazyData() {

            try{
                setLoadingDatatable(true);

                const init = formatDate(dateInit)
                const finish = formatDate(dateFinish)
                const mes = formatMonth(month)
                let url = `${BASE_URL}/api/reports/reportPaymentTeacher?page=${lazyParams.page + 1}&dateInit=${init}&dateFinish=${finish}&teacherId=${teacher}&month=${mes}&schoolYearId=${schoolYear ? schoolYear.id : null}`;
    
                await axios.get(url).then(({ data: { data: invoices } }) => {
                    const total = (invoices.meta && invoices.meta.pagination.total) || 0;
                    setTotalRecords(total);
                    const data = (invoices && invoices.data) || null;
                    setInvoices(data);
                    setLoadingDatatable(false);
                });
    
            }
            catch(error){
                console.log(error)
                console.warn('Hubo un problema al cargar los registros de reportes de recibos de docentes');
                setShowError(true);
                setLoadingDatatable(false);
                setLoading(false)
            }            
        }
        loadLazyData();
    }, [lazyParams, teacher, month, dateInit, dateFinish, schoolYear]) // eslint-disable-line react-hooks/exhaustive-deps

    const onPage = (event) => {

        let _lazyParams = { ...lazyParams, ...event };
        setLazyParams(_lazyParams);
    }

    const onSort = (event) => {
        console.log(event);
        let _lazyParams = { ...lazyParams, ...event };
        setLazyParams(_lazyParams);
    }

    const  downloadPdf = () =>{
        const init = formatDate(dateInit)
        const finish = formatDate(dateFinish)
        const mes = formatMonth(month)
        let url = `${BASE_URL}/api/reports/downloadPaymentTeacher?page=${lazyParams.page + 1}&dateInit=${init}&dateFinish=${finish}&teacherId=${teacher}&month=${mes}&schoolYearId=${schoolYear ? schoolYear.id : null}`;
        setDownload(true);
        axios({
            url: url,
            method: 'GET',
            responseType: 'blob', // Important
        }).then((response) => {
            FileDownload(response.data, 'repote-pago-de-docente.pdf');
            setDownload(false);
        }).catch((error) =>{
            toast.current.show({ severity: 'error', summary: 'Error', detail: 'Hubo un problema al generar el reporte de cobros por idioma y curso', life: 3000 });
            setDownload(false);
        });
    }
    const LeftToolbarTemplate = () => {
        return (
            <div className="card">
                <div className="p-fluid p-formgrid p-grid">
                    <div className="p-field p-col-10 p-md-2">
                        <label htmlFor="schoolYear" className="p-d-block">Año lectivo</label>
                        <Dropdown appendTo={document.body} id="schoolYear" value={schoolYear} onChange={e => setSchoolYear(e.target.value || null)} options={schoolYears} optionLabel="year" placeholder="-- Año lectivo --" style={{ width: '14rem' }} />
                    </div>
                    <div className="p-field p-col-12 p-md-3">
                        <label htmlFor="dateInit" className="p-d-block">Fecha de inicio</label>
                        <Calendar monthNavigator yearNavigator yearRange="2010:2050"  appendTo={document.body} id="dateInit" value={dateInit || undefined} viewDate={calViewDate || undefined} onViewDateChange={(e) => setCalViewDate(e.value)} onChange={(e) => setDateInit(()=>{
                            setMonth(null);
                            return   e.target.value;
                        })} locale="es" dateFormat="dd/mm/yy" />

                    </div>
                    <div className="p-field p-col-12 p-md-3">
                        <label htmlFor="dateFinish" className="p-d-block">Fecha de finalización</label>
                        <Calendar monthNavigator yearNavigator yearRange="2010:2050"  appendTo={document.body} id="dateFinish" value={dateFinish || undefined} viewDate={calViewDate || undefined} onViewDateChange={(e) => setCalViewDate(e.value)} onChange={(e) => setDateFinish(()=>{
                            setMonth(null);
                            return e.target.value
                        })} locale="es" dateFormat="dd/mm/yy" />
                    </div>
                    {/* <div className="p-field p-col-12 p-md-3">
                        <label htmlFor="month" className="p-d-block">Mes</label>
                        <Calendar id="month" value={month} onChange={(e) => setMonth(()=>{
                            setDateInit(null);
                            setDateFinish(null);
                            return e.target.value;
                        })} view="month" dateFormat="mm/yy" yearNavigator yearRange="2000:2100" />
                    </div> */}
                    <div className="p-field p-col-12 p-md-3">
                        <label htmlFor="course" className="p-d-block">Docente</label>
                        <Dropdown appendTo={document.body} id="course" value={teacher} onChange={e => setTeacher(()=>{
                            return e.target.value !== undefined ? e.target.value: null; 
                        })} options={teachers} optionLabel="completeName" optionValue="id" filter showClear filterBy="completeName" placeholder="-- Seleccione docente --" />
                    </div>
                    <div className="p-field p-col-12 p-md-3">
                    <label htmlFor="course" className="p-d-block">&nbsp;&nbsp;</label>
                        <Button label={download ? "Generando..." : "Generar PDF"} icon={download ? "pi pi-spin pi-spinner" : "pi pi-file-pdf"} className="btn-pdf" onClick={downloadPdf} disabled={download} />
                    </div>
                </div>
            </div>
        )
    }

    if (loading) {
        return (
            <Loading />
        );
    }

    if(showError){
        return(
            <Error mensaje={'Hubo un problema al cargar los registros de reportes de recibos de docentes'}></Error>
        );
    } 

    return (
        <div className="p-grid crud-demo">
            <div className="p-col-12">
                <div className="p-d-flex p-ai-center p-mb-3" style={{ gap: '1rem' }}>
                    <div style={{ width: 48, height: 48, borderRadius: 12, flexShrink: 0, background: 'linear-gradient(135deg, #3ab54a, #1a5c25)', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 14px rgba(58,181,74,0.35)' }}>
                        <i className="pi pi-wallet" style={{ color: '#fff', fontSize: '1.4rem' }}></i>
                    </div>
                    <div>
                        <h2 className="p-m-0" style={{ color: '#1a3320', fontWeight: 800, fontSize: '1.45rem', lineHeight: 1.2 }}>Pagos por docente</h2>
                        <p className="p-m-0" style={{ color: '#6c757d', fontSize: '0.875rem' }}>Recibos de docentes</p>
                    </div>
                </div>
                <div className="card" style={{ borderRadius: 12, boxShadow: '0 2px 16px rgba(0,0,0,0.07)', border: 'none' }}>
                    <Toast ref={toast} />
                    <LeftToolbarTemplate />
                    <DataTable ref={dt} value={invoices} lazy
                        paginator first={lazyParams.first} rows={10} totalRecords={totalRecords} onPage={onPage}
                        onSort={onSort} sortField={lazyParams.sortField} sortOrder={lazyParams.sortOrder}
                        loading={loadingDatatable}
                        className="datatable-responsive datatable-compact" stripedRows rowHover >
                    <Column field="date" header="Fecha"></Column>
                    <Column field="amount" header="Monto"></Column>
                    <Column field="teacher.data.completeName" header="Docente"></Column>
                    </DataTable>
                </div>
            </div>
        </div>

    );

}