import React, { useState, useEffect, useRef } from 'react';
// import { DataTable } from 'primereact/datatable';
import { TreeTable } from 'primereact/treetable';
import { Column } from 'primereact/column';
import { Toast } from 'primereact/toast';
import { Button } from 'primereact/button';
import axios from 'axios';
import { BASE_URL } from '../../helpers/BaseUrl';
import { addLocale } from 'primereact/api';
import { Dropdown } from 'primereact/dropdown';
import Error from '../../components/Error';





const FileDownload = require('js-file-download');

export default function ReportLanguajeLevelCourse() {

    addLocale('es', {
        firstDayOfWeek: 1,
        dayNames: ['domingo', 'lunes', 'martes', 'miércoles', 'jueves', 'viernes', 'sábado'],
        dayNamesShort: ['dom', 'lun', 'mar', 'mié', 'jue', 'vie', 'sáb'],
        dayNamesMin: ['D', 'L', 'M', 'X', 'J', 'V', 'S'],
        monthNames: ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'],
        monthNamesShort: ['ene', 'feb', 'mar', 'abr', 'may', 'jun', 'jul', 'ago', 'sep', 'oct', 'nov', 'dic'],
        today: 'Hoy',
        clear: 'Claro'
    });
    const [showError, setShowError] = useState(false);

    const toast = useRef(null);

    const [level, setLevel] = useState(null);
    const [languaje, setLanguaje] = useState(null);
    const [course, setCourse] = useState(null);
    const [schoolYear, setSchoolYear] = useState(null);

    const [languajes, setLanguajes] = useState(null);
    const [courses, setCourses] = useState(null);
    const [levels, setLevels] = useState(null);
    const [schoolYears, setSchoolYears] = useState(null);


    const [students, setStudents] = useState(null);
    const [chargingCourse, setChargingCourse] = useState(false);
    const [chargingLevel] = useState(false); // eslint-disable-line no-unused-vars

    const [download, setDownload] = useState(false);

    useEffect(() => {
        async function loadSchoolYear() {
            try {
                    await axios.get(`${BASE_URL}/api/schoolYears?all=1`).then(({ data: { data: { data: schoolYearss } } }) => {
                        setSchoolYears(schoolYearss);
                        setCourses(null);
                        const active = schoolYearss.find(function(y) { return y.active === true; });
                        setSchoolYear(active || null);
                    });

            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de los años lectivos');
                setShowError(true);
            }
        }
        loadSchoolYear()
    }, []); // eslint-disable-line react-hooks/exhaustive-deps

    useEffect(() => {
        async function loadLanguajes() {
            try {
                setChargingCourse(true)
                await axios.get(`${BASE_URL}/api/languajes?all=1`).then(({ data: { data: { data: languajes } } }) => {
                    setLanguajes(languajes);
                    setLevels(null);
                    setCourses(null);
                    setChargingCourse(false)

                });
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de idiomas');
                setShowError(true);
                setChargingCourse(false)

            }
        }
        loadLanguajes();
    }, []);

    useEffect(() => {
        async function loadLevels() {
            try {
                //?all=1
                if (languaje !=null){
                    setChargingCourse(true)
                    setLevels(null);
                    setCourses(null);

                    await axios.get(`${BASE_URL}/api/languajes/${languaje.id}/levels?all=1`).then(({ data: { data: { data: levels } } }) => {
                      setLevels(levels);
                      setChargingCourse(false)

                    });
                }
                
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga los niveles por idioma');
                setShowError(true);
                setChargingCourse(false)
            }
        }
        loadLevels();
    }, [languaje]); 

    useEffect(() => {
        async function loadCourse() {
            try {
                if (level !=null){
                    setChargingCourse(true)
                    setCourses(null);

                    await axios.get(`${BASE_URL}/api/levels/${level.id}/courses?all=1&schoolYear=${schoolYear.id}`).then(({ data: { data: { data: courses } } }) => {
                      setCourses(courses);
                      setChargingCourse(false)
                    });
                }
                
            } catch (error) {
                console.log(error);
                console.warn('Hubo un problema con la carga de los cursos por nivel');
                setShowError(true);
                setChargingCourse(false)
            }
        }
        loadCourse();
    }, [schoolYear, level]); // eslint-disable-line react-hooks/exhaustive-deps 

    useEffect(() => {
        async function loadLazyData() {

            try{

                 let   languajeId = null
                 let   levelId = null
                 let   courseId = null
                 let   schoolYearV = null

                if (!languaje){
                    return
                }

                if (languaje && level && schoolYear && course){
                    console.log(course.id)
                    languajeId = languaje.id
                    levelId = level.id
                    courseId = course.id
                    schoolYearV = schoolYear.id
                }
                else if (languaje && level && schoolYear ){
                    languajeId = languaje.id
                    levelId = level.id
                    schoolYearV = schoolYear.id
                }else if (languaje && level ){
                        languajeId = languaje.id
                        levelId = level.id
                }else if (languaje){
                    languajeId = languaje.id
                }
                setStudents(null);

                let url = `${BASE_URL}/api/reports/reportLanguajeLevelCourse?languajeId=${languajeId}&levelId=${levelId}&courseId=${courseId}&schoolYears=${schoolYearV}`;
                // let url = `${BASE_URL}/api/reports/assistencesByCourse?page=${lazyParams.page + 1}&dateInit=${init}&dateFinish=${finish}&courseId=${course}&month=${mes}`;
                setChargingCourse(true)

                await axios.get(url).then(( data) => {
                    setStudents(data.data);
                    setChargingCourse(false)

                });
            }catch(err){
                console.log(err);
                console.warn('Hubo un problema con la carga de alumnos');
                setShowError(true);
            }
        }
        loadLazyData();
    }, [languaje, level, schoolYear, course]) // eslint-disable-line react-hooks/exhaustive-deps

    const  downloadPdf = () =>{
        let   languajeId = null
        let   levelId = null
        let   courseId = null
        let   schoolYearV = null

       if (!languaje){
           return
       }

       if (languaje && level && schoolYear && course){
           console.log(course.id)
           languajeId = languaje.id
           levelId = level.id
           courseId = course.id
           schoolYearV = schoolYear.id
       }
       else if (languaje && level && schoolYear ){
           languajeId = languaje.id
           levelId = level.id
           schoolYearV = schoolYear.id
       }else if (languaje && level ){
               languajeId = languaje.id
               levelId = level.id
       }else if (languaje){
           languajeId = languaje.id
       }

       let url = `${BASE_URL}/api/reports/downloadReportLanguajesLevelsCourses?languajeId=${languajeId}&levelId=${levelId}&courseId=${courseId}&schoolYears=${schoolYearV}`;
        setDownload(true);
         axios({
            url: url,
            method: 'GET',
            responseType: 'blob', // Important
        }).then((response) => {
            console.log(response)
            FileDownload(response.data, 'reporte-listado-idioma-nivel-curso.pdf.pdf');
            setDownload(false);
        }).catch((e) =>{
            toast.current.show({ severity: 'error', summary: 'Error', detail: 'Hubo un problema al generar el reporte de listado  por idioma, nivel y curso', life: 3000 });
            setDownload(false);
        });
    }


    const observacionesCol = (rowData,index) =>{
        const htmlContent = rowData.data.observaciones;

        return (
          <div dangerouslySetInnerHTML={{ __html: htmlContent }} />
        );

       
    }

    const LeftToolbarTemplate = () => {
        return (
            <div className="card">
                <div className="p-fluid p-formgrid p-grid">

                    <div className="p-field p-col-10 p-md-2">
                        <label htmlFor="schoolYear" className="p-d-block">Año lectivo</label>
                        <div className="p-d-flex">
                            <Dropdown  appendTo={document.body} id="schoolYear" value={schoolYear} onChange={e => setSchoolYear(()=>{
                                    return e.target.value !== undefined ? e.target.value: null;
                            })} options={schoolYears} optionLabel="year" filter  filterBy="year" placeholder="-- Seleccione año lectivo --" style={{ width: '14rem' }}/>
                        </div>
                    </div>

                    <div className="p-field p-col-10 p-md-2">

                            <label htmlFor="languaje" className="p-d-block">Idioma</label>
                            <div className="p-d-flex">
                                <Dropdown appendTo={document.body} id="languaje" value={languaje} onChange={e => setLanguaje(()=>{
                                    return e.target.value !== undefined ? e.target.value: null;
                                })} options={languajes} optionLabel="name" filter  filterBy="name" placeholder="-- Seleccione idioma --" style={{ width: '14rem' }} className="p-mr-2"/>
                            </div>
                    </div>

                    <div className="p-field p-col-10 p-md-2">

                            <label htmlFor="level" className="p-d-block">Nivel</label>
                            <div className="p-d-flex">
                                <Dropdown appendTo={document.body} id="level" value={level} onChange={e => setLevel(()=>{
                                    return e.target.value !== undefined ? e.target.value: null;
                                })} options={levels} optionLabel="name" filter  filterBy="name" placeholder="-- Seleccione nivel --" style={{ width: '14rem' }} className="p-mr-2"/>
                            </div>
                    </div>

                    <div className="p-field p-col-10 p-md-2">
                        <label htmlFor="course" className="p-d-block">Curso</label>
                        <div style={{ position: 'relative' }}>
                            <Dropdown appendTo={document.body} id="course" value={course} onChange={e => setCourse(()=>{
                                return e.target.value !== undefined ? e.target.value: null;
                            })} options={courses} optionLabel="nameId" optionValue="id" filter filterBy="nameId"
                                disabled={chargingCourse}
                                placeholder={chargingCourse ? 'Cargando...' : '-- Seleccione curso --'}
                                style={{ width: '14rem' }}
                            />
                            {chargingCourse && (
                                <i className="pi pi-spin pi-spinner" style={{
                                    position: 'absolute', right: 38, top: '50%',
                                    transform: 'translateY(-50%)',
                                    color: '#3ab54a', fontSize: '0.85rem', pointerEvents: 'none',
                                }} />
                            )}
                        </div>
                    </div>

                    <div className="p-field p-col-10 p-md-2">
                         <label htmlFor="course" className="p-d-block">&nbsp;&nbsp;</label>
                        <Button label={download ? "Generando..." : "Generar PDF"} icon={download ? "pi pi-spin pi-spinner" : "pi pi-file-pdf"} className="btn-pdf" onClick={downloadPdf} disabled={download} />
                    </div>
                </div>
            </div>
        )
    }

    // if (loading) {
    //     return (
    //         <Loading />
    //     );
    // }

    if(showError){
        return(
            <Error mensaje={'Hubo un problema al cargar los alumnos por idioma, nivel y curso'}></Error>
        );
    } 

    return (
        <div className="p-grid crud-demo">
            <div className="p-col-12">
                <div className="p-d-flex p-ai-center p-mb-3" style={{ gap: '1rem' }}>
                    <div style={{ width: 48, height: 48, borderRadius: 12, flexShrink: 0, background: 'linear-gradient(135deg, #3ab54a, #1a5c25)', display: 'flex', alignItems: 'center', justifyContent: 'center', boxShadow: '0 4px 14px rgba(58,181,74,0.35)' }}>
                        <i className="pi pi-book" style={{ color: '#fff', fontSize: '1.4rem' }}></i>
                    </div>
                    <div>
                        <h2 className="p-m-0" style={{ color: '#1a3320', fontWeight: 800, fontSize: '1.45rem', lineHeight: 1.2 }}>Lista por idioma, nivel y curso</h2>
                        <p className="p-m-0" style={{ color: '#6c757d', fontSize: '0.875rem' }}>Alumnos por idioma, nivel y curso</p>
                    </div>
                </div>
                <div className="card" style={{ borderRadius: 12, boxShadow: '0 2px 16px rgba(0,0,0,0.07)', border: 'none' }}>
                    <Toast ref={toast} />
                    <LeftToolbarTemplate />
                    <h5>Lista de Alumnos por Idioma, Nivel y Curso</h5>
                    {/* <DataTable value={assistances} expandedRows={students} onRowToggle={(e) => setStudents(e.data)}
                        onRowExpand={onRowGroupExpand} onRowCollapse={onRowGroupCollapse}
                        rowExpansionTemplate={rowExpansionTemplate} dataKey="id" header={header}
                        ref={dt} lazy
                        paginator first={lazyParams.first} rows={10} totalRecords={totalRecords} onPage={onPage}
                        onSort={onSort} sortField={lazyParams.sortField} sortOrder={lazyParams.sortOrder}
                        loading={loadingDatatable}

                    >
                        <Column expander style={{ width: '3em' }} />
                        <Column field="date" header="Fecha"></Column>

                    </DataTable> */}



                    <TreeTable value={students} tableStyle={{ minWidth: '50rem' }}>
                    <Column field="apellido" header="Apellido" expander></Column>
                    <Column field="nombre" header="nombre"></Column>
                    <Column field="dni" header="dni"></Column>
                    <Column field="turno_escolar" header="Turno escolar"></Column>
                    <Column field="horario_ed_fisica" header="Hora de ed. fisica"></Column>
                    <Column field="observaciones" body={observacionesCol} header="Observaciones"></Column>

                    
                </TreeTable>


                </div>
            </div>
        </div>

    );

}